sql:
SELECT risk_level 
FROM asset_features 
WHERE asset_type = 'stocks';

SELECT AVG(ap.total_amount) AS average_performance
FROM asset_performance ap
JOIN asset_features af ON af.feature_id = ap.feature_id;

SELECT asset_type, COUNT(*) as asset_count
FROM asset_features
GROUP BY asset_type;

SELECT user_id, COUNT(report_id) AS number_of_reports 
FROM performance_reports 
GROUP BY user_id;

SELECT user_id AS id FROM users WHERE user_name = 'Bob Johnson'
UNION ALL
SELECT holding_id AS id FROM asset_holdings WHERE feature_id = 1;

SELECT feature_id, total_amount, absolute_held, relative_held
FROM asset_holdings
ORDER BY total_amount DESC;

SELECT af.feature_name, ap.total_amount, ap.benchmark_performance, ap.predicted_performance
FROM asset_features af
INNER JOIN asset_performance ap ON af.feature_id = ap.feature_id;

SELECT users.user_name, users.email, performance_reports.report_date, performance_reports.report_type, performance_reports.report_status
FROM users
JOIN performance_reports ON users.user_id = performance_reports.user_id;

external_knowledge:
- "hidden treasures of the financial forest" refers to asset features;
- "secret quantified power" and "overall strength" represent the logarithmized `absolute_held` and `total_amount`, respectively;
- "lesser of their actual or expected glory" symbolizes the minimum of the `predicted_performance` and `benchmark_performance`;
- "discoverers" are the individuals whose user IDs link to the performance reports;
- "dates of their revelation" and "cycle of their discovery" denote the report date and type;
- "state of their illumination" refers to the report status;
- "sparkle with more than half their potential" means assets where `relative_held` is greater than 0.5;
- "tales of valor have been finalized by their chroniclers" refers to reports that have a 'final' status.

